mapper.select:
/* SQL ID : OrgAuthGrpDAO.list 설 명 : 기관 권한의 전체 목록 */ SELECT MENU_TYCD , USER_AUTHRT_ID , AUTHRT_GRPNM , ORG_ID , USEYN , LANG_CD , AUTHRT_GRP_EXPLN , AUTHRT_GRP_SEQ , RGTR_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = RGTR_ID) AS RGTRNM , FRST_INQ_DTTM , MDFR_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = MDFR_ID) AS MOD_NM , MOD_DTTM FROM TB_LMS_AUTHRT_GRP WHERE 1 = 1
AND MENU_TYCD = #{menuType}
AND USEYN = #{useYn}
AND ORG_ID = #{orgId}
AND LANG_CD = #{langCd}
ORDER BY AUTHRT_GRP_SEQ, MOD_DTTM DESC

/* SQL ID : OrgAuthGrpDAO.listFile 설 명 : 기관 권한의 파일사용자 목록 */ SELECT MENU_TYCD , USER_AUTHRT_ID , AUTHRT_GRPNM , ORG_ID , USEYN , LANG_CD , AUTHRT_GRP_EXPLN , AUTHRT_GRP_SEQ , RGTR_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = RGTR_ID) AS RGTRNM , FRST_INQ_DTTM , MDFR_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = MDFR_ID) AS MOD_NM , MOD_DTTM FROM TB_LMS_AUTHRT_GRP WHERE 1 = 1 AND MENU_TYCD = 'HOME'
AND SYS_TYCD IN ('PROFESSOR', 'ASSISTANT', 'STUDENT')
AND USEYN = #{useYn}
AND ORG_ID = #{orgId}
AND LANG_CD = #{langCd}
ORDER BY AUTHRT_GRP_SEQ, MOD_DTTM DESC

/* SQL ID : OrgAuthGrpDAO.listInUser 설 명 : 해당 사용자가 부여 받은 권한 목록 */ SELECT MENU_TYCD , USER_AUTHRT_ID , AUTHRT_GRPNM , ORG_ID , USEYN , AUTHRT_GRP_EXPLN , AUTHRT_GRP_SEQ , RGTR_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = RGTR_ID) AS RGTRNM , FRST_INQ_DTTM , MDFR_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = MDFR_ID) AS MOD_NM , MOD_DTTM FROM TB_LMS_AUTHRT_GRP WHERE 1 = 1
AND MENU_TYCD = #{menuType}
AND USEYN = 'Y' AND USER_AUTHRT_ID IN (SELECT USER_AUTHRT_ID FROM TB_LMS_USER_AUTHRT WHERE USER_ID = #{userId} )
AND ORG_ID = #{orgId}
ORDER BY AUTHRT_GRP_SEQ

/* SQL ID : OrgAuthGrpDAO.listNotInUser 설 명 : 해당 사용자가 부여 받지 않은 권한 목록 */ SELECT MENU_TYCD , USER_AUTHRT_ID , AUTHRT_GRPNM , ORG_ID , USEYN , AUTHRT_GRP_EXPLN , AUTHRT_GRP_SEQ , RGTR_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = RGTR_ID) AS RGTRNM , FRST_INQ_DTTM , MDFR_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = MDFR_ID) AS MOD_NM , MOD_DTTM FROM TB_LMS_AUTHRT_GRP WHERE 1 = 1
AND MENU_TYCD = #{menuType}
AND USEYN = 'Y' AND USER_AUTHRT_ID NOT IN (SELECT USER_AUTHRT_ID FROM TB_LMS_USER_AUTHRT WHERE USER_ID = #{userId} )
AND ORG_ID = #{orgId}
ORDER BY AUTHRT_GRP_SEQ

/* SQL ID : OrgAuthGrpDAO.select 설 명 : 기관 권한의 정보 조회 */ SELECT MENU_TYCD , USER_AUTHRT_ID , AUTHRT_GRPNM , ORG_ID , USEYN , LANG_CD , AUTHRT_GRP_EXPLN , AUTHRT_GRP_SEQ , RGTR_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = RGTR_ID) AS RGTRNM , FRST_INQ_DTTM , MDFR_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = MDFR_ID) AS MOD_NM , MOD_DTTM FROM TB_LMS_AUTHRT_GRP WHERE 1 = 1
AND MENU_TYCD = #{menuType}
AND #{authGrpCd} LIKE CONCAT('%',AUTHRT_GRPCD,'%')
AND ORG_ID = #{orgId}
AND LANG_CD = #{langCd}

mapper.insert:
/*
	 SQL ID : OrgAuthGrpDAO.insert
	 설  명 : 기관 권한의 정보 등록
*/
INSERT INTO TB_LMS_AUTHRT_GRP (
    MENU_TYCD
    , USER_AUTHRT_ID
    , AUTHRT_GRPNM
    , ORG_ID
    , USEYN
    , LANG_CD
    , AUTHRT_GRP_EXPLN
    , AUTHRT_GRP_SEQ
    , RGTR_ID
    , FRST_INQ_DTTM
    , MDFR_ID
    , MOD_DTTM
) VALUES (
    #{menuType}
    , #{authGrpCd}
    , #{authGrpNm}
    , #{orgId}
    , #{useYn}
    , #{authGrpDesc}
    , ( SELECT IFNULL(MAX(A.AUTHRT_GRP_SEQ),0)+1
          FROM TB_LMS_AUTHRT_GRP A
         WHERE A.MENU_TYCD = #{menuType} )
    , #{rgtrId}
    , FN_DTTM()
    , #{mdfrId}
    , FN_DTTM()
)

mapper.update:
	/*
		 SQL ID : OrgAuthGrpDAO.update
		 설  명 : 기관 권한의 정보 수정
 	*/
	UPDATE TB_LMS_AUTHRT_GRP
	   SET USEYN = #{useYn}

	   	 ,AUTHRT_GRPNM = #{authGrpNm} 


	     , AUTHRT_GRP_EXPLN = #{authGrpDesc}


	     , AUTHRT_GRP_SEQ = #{authGrpOdr}

	     , MDFR_ID = #{mdfrId}
	     , MOD_DTTM = FN_DTTM()
	 WHERE MENU_TYCD = #{menuType}
	   AND USER_AUTHRT_ID = #{authGrpCd}

	   AND ORG_ID = #{orgId}


		AND LANG_CD = #{langCd}

mapper.delete:
/*
	 SQL ID : OrgAuthGrpDAO.delete
	 설  명 : 기관 권한의 정보 삭제
*/
DELETE FROM TB_LMS_AUTHRT_GRP
WHERE MENU_TYCD = #{menuType}
	AND USER_AUTHRT_ID = #{authGrpCd}
	AND ORG_ID = #{orgId}

	AND LANG_CD = #{langCd}
